    m_offsets = pid_m * BLOCK_M + tl.arange(0, BLOCK_M)
    oc_offsets = pid_oc * BLOCK_OC + tl.arange(0, BLOCK_OC)
    m_mask = m_offsets < (num_batches * out_height * out_width)
    oc_mask = oc_offsets < out_channels
    pix_n = m_offsets // (out_height * out_width)
    pix_hw = m_offsets % (out_height * out_width)
    pix_h = pix_hw // out_width
    pix_w = pix_hw % out_width
    K_TOTAL: tl.constexpr = in_channels * 9
    BM_T: tl.constexpr = BLOCK_M * BTILE_T
    WINDOW_T: tl.constexpr = BTILE_T * REUSE_GROUPS
    if USE_TF32:
        bias = tl.load(b_ptr + oc_offsets, mask=oc_mask, other=0.0).to(tl.float32)
    else:
        bias = tl.load(b_ptr + oc_offsets, mask=oc_mask, other=0.0).to(tl.float16)
    v_offsets = pix_n[:, None] * (out_channels * out_height * out_width) + oc_offsets[None, :] * (out_height * out_width) + pix_hw[:, None]
    if USE_TF32:
        v_state = tl.load(v_ptr + v_offsets, mask=m_mask[:, None] & oc_mask[None, :], other=0.0).to(tl.float32)
